const fo="fn pn(vNormalW:vec3<f32>,pw:vec3<f32>,uv:vec2<f32>,bs:f32)->vec3<f32>{let normalSample=textureSample(bT,bS,uv).rgb*2.0-1.0;let N=normalize(vNormalW)*bs;let dp1=dpdx(pw);let dp2=-dpdy(pw);let duv1=dpdx(uv);let duv2=-dpdy(uv);let dp2perp=cross(dp2,N);let dp1perp=cross(N,dp1);var tangent=dp2perp*duv1.x+dp1perp*duv2.x;var bitangent=dp2perp*duv1.y+dp1perp*duv2.y;let det=max(dot(tangent,tangent),dot(bitangent,bitangent));let invmax=select(inverseSqrt(det),0.0,det==0.0);let cotangentFrame=mat3x3<f32>(tangent*invmax,bitangent*invmax,N);return normalize(cotangentFrame*normalSample);}",sr="const E_FOG:f32=2.71828;fn calcFogFactor(fogDistance:vec3<f32>)->f32{var fogCoeff:f32=1.0;let fogMode=scene.vFogInfos.x;let fogStart=scene.vFogInfos.y;let fogEnd=scene.vFogInfos.z;let fogDensity=scene.vFogInfos.w;let dst=length(fogDistance);if(fogMode==3.0){fogCoeff=(fogEnd-dst)/(fogEnd-fogStart);}else if(fogMode==1.0){fogCoeff=1.0/pow(E_FOG,dst*fogDensity);}else if(fogMode==2.0){fogCoeff=1.0/pow(E_FOG,dst*dst*fogDensity*fogDensity);}return clamp(fogCoeff,0.0,1.0);}";export{fo as W,sr as a};